-- Example hex string (as given in your example)
hex_string = [[]]
-- Function to convert hex string to binary data
function from_hex(hex)
    return (hex:gsub("..", function(byte)
        return string.char(tonumber(byte, 16))
    end))
end

-- Convert the hex string to binary data
local bytecode = from_hex(hex_string)

-- Write the binary data to a file
local file = io.open("output_bytecode.luac", "wb")  -- "wb" mode opens the file in binary mode for writing
file:write(bytecode)
file:close()

print("Bytecode written to output_bytecode.luac")

